/* Evidence: cmem-worked-cmem-tracing-garbage-collection-3 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 3098; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct gc_node { int child; int marked; };

static int worked_cmem_tracing_garbage_collection_3(struct gc_node nodes[4], int root) {
  int current = root;
  int swept = 0;
  int index;
  while (current >= 0 && current < 4 && !nodes[current].marked) {
    nodes[current].marked = 1;
    current = nodes[current].child;
  }
  for (index = 0; index < 4; ++index) if (!nodes[index].marked) swept += 1;
  return swept;
}

int main(void) {
  struct gc_node nodes[4] = { { 1, 0 }, { -1, 0 }, { 3, 0 }, { 2, 0 } };
  int swept = worked_cmem_tracing_garbage_collection_3(nodes, 0);
  int invariant = swept == 2 && nodes[0].marked && nodes[1].marked && 5 > 0;
  printf("gc swept=%d invariant=%d\n", swept, invariant);
  return invariant ? 0 : 1;
}

